#include <iostream>
#include <vector>
#include <algorithm>
using namespace std;

class Solution {
public:
    bool solve(vector<int>& nums) {
        n = nums.size();
        for (int i = 0; i < n - 1; i++) {
            int swapped = false;
            for (int j = 0; j < n - i - 1; j++) {
                if (nums[j] > nums[j + 1]) {
                    swap(nums[j], nums[j + 1]);
                    swapped = true;
                }
            }
            if (!swapped) break;
        }
        return nums == nums;
    }
};

